package main

import (
    "fmt"
    "time"
)

func main() {
    // ---- Basic select ----
    ch1 := make(chan string)
    ch2 := make(chan string)

    go func() {
        time.Sleep(100 * time.Millisecond)
        ch1 <- "from ch1"
    }()

    go func() {
        time.Sleep(50 * time.Millisecond)
        ch2 <- "from ch2"
    }()

    select {
    case msg1 := <-ch1:
        fmt.Println(msg1)
    case msg2 := <-ch2:
        fmt.Println(msg2)
    }

    // ---- Select with timeout ----
    ch3 := make(chan string)

    select {
    case msg := <-ch3:
        fmt.Println(msg)
    case <-time.After(100 * time.Millisecond):
        fmt.Println("Timeout: no message received")
    }

    // ---- Select with default (non-blocking) ----
    ch4 := make(chan int)

    select {
    case v := <-ch4:
        fmt.Println("Received:", v)
    default:
        fmt.Println("No value ready")
    }

    // ---- Select in a loop ----
    done := make(chan bool)
    messages := make(chan string)

    go func() {
        for i := 0; i < 5; i++ {
            messages <- fmt.Sprintf("Message %d", i)
            time.Sleep(50 * time.Millisecond)
        }
        done <- true
    }()

    loop:
    for {
        select {
        case msg := <-messages:
            fmt.Println(msg)
        case <-done:
            fmt.Println("Done")
            break loop
        case <-time.After(200 * time.Millisecond):
            fmt.Println("Timeout")
            break loop
        }
    }
}

